const raw = $input.first().json.body ?? $input.first().json;

const validLevels = ['debug', 'info', 'warn', 'error'];

const entry = {
  workflow_name: String(raw.workflow_name ?? 'unknown').slice(0, 100),
  tool_name:     raw.tool_name ? String(raw.tool_name).slice(0, 100) : null,
  level:         validLevels.includes(raw.level) ? raw.level : 'info',
  message:       String(raw.message ?? '').slice(0, 2000),
  metadata:      (raw.metadata && typeof raw.metadata === 'object') ? raw.metadata : {},
  session_id:    raw.session_id ? String(raw.session_id).slice(0, 100) : null,
  created_at:    raw.ts ?? new Date().toISOString(),
};

return [{ json: entry }];

